function solve(sx: number, sy: number, tx: number, ty: number): number {
    let steps = 0;
    while (tx > sx && ty > sy) {
        if (tx > ty) {
            const k = Math.floor((tx - sx) / ty);
            if (k === 0) break;
            steps += k;
            tx -= k * ty;
        } else {
            const k = Math.floor((ty - sy) / tx);
            if (k === 0) break;
            steps += k;
            ty -= k * tx;
        }
