            steps += (ty - sy) / tx;
            return steps;
        }
    } else if (ty === sy) {
        if (tx >= sx && (tx - sx) % ty === 0) {
            steps += (tx - sx) / ty;
            return steps;
        }
    }
    return -1;
}
